('VPS_2018_parent_inventory_3', 'VPS', 2018, 'parent', 'Thành phẩm', 'finished_goods', 55981582486.0, 3223605075.0, NULL),
('VPS_2018_parent_inventory_4', 'VPS', 2018, 'parent', 'Hàng hóa', 'finished_goods', 5484204362.0, 0.0, NULL),
('VPS_2018_parent_inventory_5', 'VPS', 2018, 'parent', 'Chi phí thuê lại quyền sử dụng đất tại Khu Công nghiệp Đức Hòa 1', 'construction_in_progress', 68711530000.0, 0.0, 'Công ty thuê lại quyền sử dụng đất của Công ty Cổ phần Khai thác Hạnh Phúc theo Hợp đồng số 18-10/HĐTLD và 19-10/HĐTLD ngày 24/10/2017 với các thông tin chi tiết: Địa chỉ: Khu Công nghiệp Đức Hòa 1, huyện Đức Hòa, tỉnh Long An; Mục đích: Thành lập Chi nhánh Long An và xây dựng Nhà máy gia công, sang chai, đóng gói thuốc Bảo vệ thực vật; Thời hạn thuê đất: đến ngày 05/12/2058; Tổng giá trị hợp đồng: 79.563.825.000 đồng (đã bao gồm VAT); Tiến độ thực hiện: Đến ngày 31/12/2018, Công ty đã thành lập Chi nhánh Long An và đang thực hiện các thủ tục pháp lý để chuẩn bị xây dựng nhà máy. Đồng thời, Công ty đã thanh toán cho Công ty Cổ phần Khai thác Hạnh Phúc 10/11 đợt đóng tiền theo Hợp đồng thuê lại quyền sử dụng đất.'),
('VPS_2018_parent_inventory_6', 'VPS', 2018, 'parent', 'Dự án Nhà máy sản xuất thuốc phòng trừ nấm bệnh Validamycin', 'construction_in_progress', 0.0, 0.0, NULL),
('VPS_2018_parent_inventory_7', 'VPS', 2018, 'parent', 'Dự án Nhà máy sản xuất nông dược và gia dụng tại Nam Định', 'construction_in_progress', 3181818182.0, 0.0, 'Dự án nhà máy nông dược và gia dụng tại Nam Định với các thông tin chi tiết: Địa chỉ: xã Nghĩa Lạc, huyện Nghĩa Hưng, tỉnh Nam Định; Tiến độ thực hiện: Đến thời điểm 31/12/2018, Công ty đã phát sinh các khoản chi phí khảo sát địa hình, lập Báo cáo đầu tư, Báo cáo thiết kế cơ sở. Tuy nhiên do dự án nằm trong hành lang thoát lũ không được xây dựng các công trình nên không thể tiếp tục thực hiện. Hiện nay dự án ngừng thực hiện theo Quyết định số 10/2018/NQ-TST-HĐQT ngày 05/12/2018 của Hội đồng Quản trị và Công ty đang lập phương án xử lý cụ thể đối với dự án này.'),
('VPS_2018_parent_inventory_8', 'VPS', 2018, 'parent', 'Dự án đầu tư mở rộng và cải tạo nhà máy nông dược Bình Dương', 'construction_in_progress', 0.0, 0.0, NULL),
('VPS_2018_parent_inventory_9', 'VPS', 2018, 'parent', 'Dự án bảo vệ môi trường và quản lý chất thải (lò đốt chất thải)', 'construction_in_progress', 1615313635.0, 0.0, 'Dự án Lò đốt chất thải tại Nhà máy Nông dược Bình Dương với các thông tin chi tiết: Địa chỉ: phường Bình Thắng, thị xã Dĩ An, tỉnh Bình Dương; Tổng mức đầu tư: 1.767.900.000 đồng; Tiến độ thực hiện: Đã thực hiện xong và nghiệm thu cơ sở trong năm 2015. Tuy nhiên Lò đốt chất thải chưa được Bộ Tài Nguyên và Môi trường phê duyệt để đi vào hoạt động. Hiện nay dự án đã dừng thực hiện theo Nghị quyết số 03/NQ-TST-HĐQT ngày 30/05/2018 của Hội đồng Quản trị. Công ty đang lập phương án xử lý cụ thể đối với dự án này.'),
('VPS_2018_parent_inventory_10', 'VPS', 2018, 'parent', 'Công trình xây dựng cơ bản khác', 'construction_in_progress', 0.0, 0.0, NULL),
