('VPS_2017_parent_inventory_1', 'VPS', 2017, 'parent', 'Thành phẩm', 'finished_goods', 71597630423.0, 3118496699.0, 'Thành phẩm thuốc bảo vệ thực vật và nông dược'),
('VPS_2017_parent_inventory_2', 'VPS', 2017, 'parent', 'Hàng hóa', 'finished_goods', 5046146935.0, NULL, 'Hàng hóa kinh doanh thương mại'),
