('VPS_2017_parent_inventory_5', 'VPS', 2017, 'parent', 'Dự án Nhà máy sản xuất thuốc phòng trừ sâu bệnh Validamycin', 'real_estate_project', 843134163.0, NULL, 'Tại KCN An Nghiệp, Sóc Trăng. Tổng vốn đầu tư 90.384.000.000 đồng. Đã hoàn thành đền bù, giải phóng mặt bằng.'),
('VPS_2017_parent_inventory_6', 'VPS', 2017, 'parent', 'Nhà máy nông dược và gia dụng tại Nam Định', 'real_estate_project', 3181818182.0, NULL, 'Xã Nghĩa Lạc, Huyện Nghĩa Hưng, Nam Định. Đang chờ cấp phép xây dựng.'),
