('VPI_2018_consolidated_inventory_0', 'VPI', 2018, 'consolidated', 'Dự án Thảo Điền - TP. HCM', 'real_estate_project', 165429856602.0, NULL, 'Nhận chuyển nhượng từ Công ty TNHH Xây dựng Thế Minh, tổng giá trị 162.000.000.000 đồng. Giấy chứng nhận quyền sử dụng đất số BA881005 ngày 15/01/2010, diện tích 4.967 m2, mục đích xây dựng chung cư.'),
('VPI_2018_consolidated_inventory_1', 'VPI', 2018, 'consolidated', 'Dự án KĐT An Hưng', 'real_estate_project', 729658254632.0, NULL, 'Nhận chuyển nhượng từ Công ty CP Đầu tư Đô thị An Hưng, tổng giá trị 747.060.300.000 đồng. Giấy chứng nhận quyền sử dụng đất số CC216528 ngày 14/12/2015, diện tích 35.574 m2, tổ hợp thương mại dịch vụ và căn hộ cao cấp.'),
('VPI_2018_consolidated_inventory_2', 'VPI', 2018, 'consolidated', 'Dự án Khu hỗn hợp 138B Giảng Võ', 'real_estate_project', 592275233702.0, NULL, 'Số 138B Giảng Võ, phường Kim Mã, quận Ba Đình, Hà Nội. Diện tích khoảng 9.031 m2. Chức năng: dịch vụ, thương mại, nhà trẻ, văn phòng, khách sạn căn hộ, căn hộ ở, nhà sinh hoạt cộng đồng và nhà ở thấp tầng.'),
('VPI_2018_consolidated_inventory_3', 'VPI', 2018, 'consolidated', 'Dự án căn hộ chung cư Luxury Tower', 'real_estate_project', 466323229473.0, NULL, 'Nhận chuyển nhượng 185 căn hộ từ tầng 05 đến tầng 20 Tòa Chung cư Luxury Tower tại 106 đường Nguy Như Kon Tum, phường Nhân Chính, quận Thanh Xuân, Hà Nội từ Công ty CP Đầu tư và Phát triển nhà Hà Nội số 41 theo HĐ ngày 18/08/2018.'),
('VPI_2018_consolidated_inventory_4', 'VPI', 2018, 'consolidated', 'Dự án Hồ Tây - Đăng Thai Mai', 'real_estate_project', 157143508927.0, NULL, 'Hợp tác với Công ty TNHH Hồ Tây một thành viên. Hợp đồng số 60/HĐTN/CTHT ngày 03/02/2016 về cho thuê Tòa 1 và khoản thu Tòa 2 Dự án Khu Dịch vụ căn hộ khách sạn Hồ Tây tại ngách 17/35, đường Đăng Thai Mai, phường Quảng An, quận Tây Hồ. Thời hạn từ 03/02/2016 đến 26/09/2064.'),
('VPI_2018_consolidated_inventory_5', 'VPI', 2018, 'consolidated', 'Dự án Khu hỗn hợp nhà ở, thương mại và văn phòng số 83 Hào Nam', 'real_estate_project', 376561656954.0, NULL, '83 Hào Nam, phường Ô Chợ Dừa, quận Đống Đa, Hà Nội. Hợp đồng hợp tác đầu tư 01/2017/HĐ-HTĐT ngày 28/04/2017 giữa Công ty CP Đầu tư Văn Phú số 2 và Công ty CP In và Văn hóa phẩm. Dùng thế chấp cho vay ngân hàng.'),
('VPI_2018_consolidated_inventory_6', 'VPI', 2018, 'consolidated', 'Dự án Văn Phú Complex', 'real_estate_project', 57335204295.0, NULL, NULL),
('VPI_2018_consolidated_inventory_7', 'VPI', 2018, 'consolidated', 'Dự án BT xây dựng tuyến đường Phạm Văn Đồng - Gò Dưa', 'construction_in_progress', 198124067192.0, NULL, 'Dự án đầu tư xây dựng đoạn tuyến kết nối từ đường Phạm Văn Đồng đến nút giao thông Gò Dưa (Quốc lộ 1) theo hình thức Hợp đồng xây dựng - chuyển giao (BT).'),
