('VPI_2017_parent_inventory_1', 'VPI', 2017, 'parent', 'Chi phí sản xuất, kinh doanh dở dang', 'real_estate_project', 914882040350.0, 0.0, 'Bao gồm Dự án nhà ở thấp tầng V5+V6 - KĐT Văn Phú, Dự án Thảo Điền - TP. HCM, Dự án KĐT An Hưng, và các dự án khác.'),
('VPI_2017_parent_inventory_2', 'VPI', 2017, 'parent', 'Hàng hoá', 'finished_goods', 89311216.0, 0.0, NULL),
('VPI_2017_parent_inventory_3', 'VPI', 2017, 'parent', 'Dự án nhà ở thấp tầng V5+V6 - KĐT Văn Phú', 'real_estate_project', 3371147003.0, 0.0, 'Dự án nhà ở thấp tầng V5+V6 được xây dựng tại lô đất V5 và V6 thuộc khu đô thị Văn Phú, có diện tích quy hoạch là 18.430 m2. Dự án bao gồm 148 ô liền kề có diện tích 73 - 215 m2 với mật độ xây dựng dưới 60%. Tính đến thời điểm 31/12/2017, có 147 ô liền kề đã ký Hợp đồng chuyển nhượng quyền sử dụng đất ở và quyền sở hữu nhà ở và đã bàn giao đưa vào sử dụng.'),
('VPI_2017_parent_inventory_4', 'VPI', 2017, 'parent', 'Dự án Thảo Điền - TP. HCM', 'real_estate_project', 163254170163.0, 0.0, 'Dự án Thảo Điền - TP.HCM được nhận chuyển nhượng từ Công ty TNHH Xây dựng Thế Minh, tổng giá trị chuyển nhượng đã bao gồm thuế GTGT là 162.000.000.000 đồng. Công ty được cấp Giấy chứng nhận quyền sử dụng đất cho Dự án số BA881005 ngày 15/01/2010, tổng diện tích 4.967 m2, mục đích sử dụng để xây dựng chung cư.'),
('VPI_2017_parent_inventory_5', 'VPI', 2017, 'parent', 'Dự án KĐT An Hưng', 'real_estate_project', 700949671131.0, 0.0, 'Dự án KĐT An Hưng được nhận chuyển nhượng từ Công ty CP Đầu tư Đô thị An Hưng, tổng giá trị chuyển nhượng đã bao gồm thuế GTGT là 747.060.300.000 đồng. Công ty được cấp Giấy chứng nhận quyền sử dụng đất cho Dự án số CC216528 ngày 14/12/2015, tổng diện tích 35.574 m2, mục đích sử dụng để thực hiện Dự án xây dựng công trình tổ hợp thương mại dịch vụ và căn hộ cao cấp An Hưng.'),
('VPI_2017_parent_inventory_6', 'VPI', 2017, 'parent', 'Các dự án khác', 'real_estate_project', 47307052053.0, 0.0, NULL),
('VPI_2017_parent_inventory_7', 'VPI', 2017, 'parent', 'Dự án Nam Sầm Sơn - Thanh Hoá', 'real_estate_project', 45302288093.0, 0.0, 'Dự án Nam Sầm Sơn - Thanh Hóa được chấp thuận đầu tư xây dựng và kinh doanh hạ tầng Khu biệt thự Hùng Sơn - Nam Sầm Sơn theo Văn bản số 4038/QĐ-CT ngày 15/12/2004 của Ủy ban nhân dân tỉnh Thanh Hóa, tổng diện tích 26,09 ha.'),
