('VPI_2017_consolidated_inventory_7', 'VPI', 2017, 'consolidated', 'Dự án Nam Sầm Sơn - Thanh Hóa', 'construction_in_progress', 45302288093.0, NULL, 'Xây dựng và kinh doanh hạ tầng Khu biệt thự Hùng Sơn - Nam Sầm Sơn theo Văn bản số 4038/QĐ-CT ngày 15/12/2004 của UBND tỉnh Thanh Hóa. Tổng diện tích 26,09 ha. Công ty đánh giá giá trị có thể thu hồi tối thiểu bằng giá gốc.'),
('VPI_2017_consolidated_inventory_8', 'VPI', 2017, 'consolidated', 'Dự án 83 Hào Nam', 'construction_in_progress', 42248477222.0, NULL, 'Khu hỗn hợp nhà ở, thương mại và văn phòng số 83 Hào Nam, phường Ô Chợ Dừa, quận Đống Đa, Hà Nội. Thực hiện theo hợp đồng hợp tác đầu tư 01/2017/HĐ-HTĐT ngày 28/04/2017 giữa Công ty CPĐT Văn Phú số 2 và Công ty CP In và Văn hóa phẩm.'),
('VPI_2017_consolidated_inventory_9', 'VPI', 2017, 'consolidated', 'Dự án Văn Phú Complex', 'construction_in_progress', 40940516513.0, NULL, 'Tòa nhà hỗn hợp Văn Phú Complex tại phường Mỹ Đình 2, quận Nam Từ Liêm, Hà Nội. Thực hiện theo thỏa thuận liên danh số 06A/2016/TTLD ngày 18/08/2016 giữa Công ty CPĐT Văn Phú số 2, Công ty CPĐT Văn Phú - Invest và Công ty TNHH An Quý Hưng.'),
('VPI_2017_consolidated_inventory_10', 'VPI', 2017, 'consolidated', 'Các dự án khác', 'real_estate_project', 69698993756.0, NULL, 'Tổng hợp các dự án bất động sản khác đang triển khai.'),
('VPI_2016_consolidated_inventory_0', 'VPI', 2016, 'consolidated', 'Dự án nhà ở thấp tầng V5+V6 - KĐT Văn Phú', 'real_estate_project', 192766871955.0, NULL, 'Dự án được xây dựng tại lô đất V5 và V6 thuộc khu đô thị Văn Phú, có diện tích quy hoạch là 18.430 m2. Dự án bao gồm 148 ô liền kề có diện tích 73 - 215 m2 với mật độ xây dựng dưới 60%.'),
('VPI_2016_consolidated_inventory_1', 'VPI', 2016, 'consolidated', 'Dự án KĐT An Hưng', 'real_estate_project', 699949203659.0, NULL, 'Dự án được nhận chuyển nhượng từ Công ty CP Đầu tư Đô thị An Hưng, tổng giá trị chuyển nhượng đã bao gồm thuế GTGT là 747.060.300.000 đồng. Công ty được cấp Giấy chứng nhận quyền sử dụng đất cho Dự án số CC216528 ngày 14/12/2015, tổng diện tích 35.574 m2.'),
('VPI_2016_consolidated_inventory_2', 'VPI', 2016, 'consolidated', 'Dự án Thảo Điền - TP. HCM', 'real_estate_project', 163245944314.0, NULL, 'Dự án được nhận chuyển nhượng từ Công ty TNHH Xây dựng Thế Minh, tổng giá trị chuyển nhượng đã bao gồm thuế GTGT là 162.000.000.000 đồng. Công ty được cấp Giấy chứng nhận quyền sử dụng đất cho Dự án số BA881005 ngày 15/01/2010, tổng diện tích 4.967 m2.'),
('VPI_2016_consolidated_inventory_3', 'VPI', 2016, 'consolidated', 'Dự án Nam Sầm Sơn - Thanh Hoá', 'real_estate_project', 39576448077.0, NULL, 'Dự án được chấp thuận đầu tư xây dựng và kinh doanh hạ tầng Khu biệt thự Hùng Sơn - Nam Sầm Sơn theo Văn bản số 4038/QĐ-CT ngày 15/12/2004 của Ủy ban nhân dân tỉnh Thanh Hóa, tổng diện tích 26,09 ha.'),
