('VPI_2018_parent_inventory_0', 'VPI', 2018, 'parent', 'Dự án KĐT An Hưng', 'real_estate_project', 729658254632.0, NULL, 'Tổ hợp thương mại dịch vụ và căn hộ cao cấp An Hưng, phường La Khê và Dương Nội, quận Hà Đông. Nhận chuyển nhượng từ Công ty CP Đầu tư Đô thị An Hưng, giá trị 747.06 tỷ VND. Diện tích 35,574 m2. Hàng tồn kho dùng để thế chấp vay ngân hàng 729.66 tỷ VND.'),
('VPI_2018_parent_inventory_1', 'VPI', 2018, 'parent', 'Dự án căn hộ chung cư để bán và văn phòng làm việc để cho thuê (Luxury Tower)', 'real_estate_project', 466323229473.0, NULL, 'Nhận chuyển nhượng 185 căn hộ từ tầng 05 đến tầng 20 Tòa Chung cư Luxury Tower tại 106 đường Nguy Như Kon Tum, phường Nhân Chính, quận Thanh Xuân, Hà Nội từ Công ty CP Đầu tư và Phát triển nhà Hà Nội số 41 theo HĐ ngày 18/08/2018.'),
('VPI_2018_parent_inventory_2', 'VPI', 2018, 'parent', 'Dự án Thảo Điền - TP. Hồ Chí Minh', 'real_estate_project', 165429856602.0, NULL, 'Nhận chuyển nhượng từ Công ty TNHH Xây dựng Thế Minh, tổng giá trị 162 tỷ VND. Giấy chứng nhận quyền sử dụng đất số BA881005 ngày 15/01/2010, diện tích 4,967 m2, mục đích xây dựng chung cư.'),
('VPI_2018_parent_inventory_3', 'VPI', 2018, 'parent', 'Dự án Hồ Tây - Đặng Thai Mai', 'real_estate_project', 157143508927.0, NULL, 'Hợp tác với Công ty TNHH Hồ Tây một thành viên trên cơ sở HĐ số 60/HĐTN/CTHT ngày 03/02/2016. Thuê Tòa 1 và khoản thu Tòa 2 Dự án Khu Dịch vụ căn hộ khách sạn Hồ Tây. Thời hạn hợp đồng đến 26/09/2064.'),
('VPI_2018_parent_inventory_4', 'VPI', 2018, 'parent', 'Dự án Lộc Bình (tỉnh Thừa Thiên Huế)', 'construction_in_progress', 5988549808.0, NULL, 'Chi phí xây dựng cơ bản dở dang thuộc Công ty TNHH Văn Phú Resort - Lộc Bình.'),
('VPI_2018_parent_inventory_5', 'VPI', 2018, 'parent', 'Dự án Hoành Bồ (tỉnh Quảng Ninh)', 'construction_in_progress', 2422171187.0, NULL, 'Chi phí xây dựng cơ bản dở dang.'),
('VPI_2018_parent_inventory_6', 'VPI', 2018, 'parent', 'Các dự án xây dựng cơ bản khác', 'construction_in_progress', 3979352228.0, NULL, 'Tổng hợp chi phí xây dựng cơ bản dở dang khác.'),
('VPI_2018_parent_inventory_7', 'VPI', 2018, 'parent', 'Các dự án bất động sản khác', 'real_estate_project', 17216852991.0, NULL, 'Tổng hợp các dự án bất động sản khác đang triển khai (chi phí sản xuất kinh doanh dở dang).'),
('VPH_2025_consolidated_inventory_0', 'VPH', 2025, 'consolidated', 'Dự án khu chung cư Phú Thuận(La Casa)', 'real_estate_project', 26891508040.0, NULL, 'Dự án đã hoàn thiện và thực hiện chuyển nhượng từ các năm trước. Hiện tại Công ty đang thực hiện tiếp các thủ tục để chuyển nhượng các phần diện tích còn lại của dự án (tương đương 1 căn hộ và khu đất có chức năng y tế).'),
('VPH_2025_consolidated_inventory_1', 'VPH', 2025, 'consolidated', 'Dự án khu dân cư Nhơn Đức', 'real_estate_project', 10763334917.0, NULL, 'Công ty đang tiếp tục hoàn thiện thủ tục triển khai thực hiện tiếp phần dự án trường học của Khu Dân cư Nhơn Đức (tương đương 6.007m2 đất).'),
('VPH_2025_consolidated_inventory_2', 'VPH', 2025, 'consolidated', 'Dự án khu dân cư Phú Mỹ', 'real_estate_project', 66064452244.0, NULL, 'Công ty đang thực hiện chuyển nhượng các lô nền còn lại thuộc Khu dân cư Phú Mỹ (tương đương 1.440m2), đồng thời Công ty đang hoàn thiện thủ tục pháp lý để tiếp tục thực hiện phần dự án trên khu đất 6000m2 đã được ngầm hóa đường dây 110 kV đi ngang qua diện tích khu đất.'),
('VPH_2025_consolidated_inventory_3', 'VPH', 2025, 'consolidated', 'Dự án khu dân cư Phú Xuân', 'real_estate_project', 76824489451.0, NULL, 'Đây là phần chi phí liên quan đến phần Dự án nhà trẻ trong Khu dân cư Phú Xuân, có diện tích 9.722 m2. Cho đến hiện tại, Công ty vẫn đang tiếp tục hoàn thiện thủ tục pháp lý để tiếp tục triển khai thực hiện dự án.'),
('VPH_2025_consolidated_inventory_4', 'VPH', 2025, 'consolidated', 'Dự án khu dân cư Hoàng Quốc Việt', 'real_estate_project', 1149207700.0, NULL, NULL),
('VPH_2025_consolidated_inventory_5', 'VPH', 2025, 'consolidated', 'Dự án khu nhà ở Nhơn Đức mở rộng', 'real_estate_project', 5630558695.0, NULL, 'Bao gồm các chi phí đền bù đất và một số chi phí thiết kế liên quan đến dự án Khu dân cư tại xã Nhơn Đức, Nhà Bè, diện tích dự án do Công ty thực hiện khoản 1.007 m2. Hiện tại, Công ty đang thực hiện tiếp các thủ tục để chuyển nhượng phần diện tích còn lại này của dự án.'),
('VPH_2025_consolidated_inventory_6', 'VPH', 2025, 'consolidated', 'Thành phẩm', 'finished_goods', 5031197317.0, NULL, NULL),
('VPH_2025_consolidated_inventory_7', 'VPH', 2025, 'consolidated', 'Dự án khu dân cư Quận 2', 'construction_in_progress', 122597782094.0, NULL, 'Dự án đang tạm ngưng triển khai chờ phương án của cơ quan nhà nước.');
