('VPH_2024_consolidated_inventory_0', 'VPH', 2024, 'consolidated', 'Dự án khu chung cư Phú Thuận (La Casa)', 'real_estate_project', 35236637632.0, NULL, 'Dự án đã hoàn thiện, Công ty đang chuyển nhượng phần diện tích còn lại (803m2 căn hộ, tầng 3 thương mại, 5.100m2 đất y tế)'),
('VPH_2024_consolidated_inventory_1', 'VPH', 2024, 'consolidated', 'Dự án khu dân cư Nhơn Đức', 'real_estate_project', 12213551895.0, NULL, 'Đang chuyển nhượng lô nền còn lại (163m2) và hoàn thiện thủ tục dự án trường học (6.007m2 đất). QSDĐ được thế chấp cho khoản vay Vietcombank'),
('VPH_2024_consolidated_inventory_2', 'VPH', 2024, 'consolidated', 'Dự án khu dân cư Phú Mỹ', 'real_estate_project', 65941540669.0, NULL, 'Đang chuyển nhượng lô nền còn lại (1.440m2), đang hoàn thiện pháp lý khu đất 6.000m2 đã ngầm hóa đường dây 110kV'),
('VPH_2024_consolidated_inventory_3', 'VPH', 2024, 'consolidated', 'Dự án khu dân cư Phú Xuân (Nhà trẻ)', 'real_estate_project', 76709637514.0, NULL, 'Phần Dự án nhà trẻ trong Khu dân cư Phú Xuân, diện tích 9.722 m2. Công ty đang hoàn thiện thủ tục pháp lý để triển khai'),
('VPH_2024_consolidated_inventory_4', 'VPH', 2024, 'consolidated', 'Dự án khu nhà ở Nhơn Đức mở rộng', 'real_estate_project', 5630558695.0, NULL, 'Chi phí đền bù đất và thiết kế liên quan đến dự án Khu dân cư tại xã Nhơn Đức, Nhà Bè, diện tích khoảng 1.007 m2'),
('VPH_2024_consolidated_inventory_5', 'VPH', 2024, 'consolidated', 'Dự án khu dân cư Quận 2 (Bình Trung Đông - Cát Lái)', 'real_estate_project', 122597782094.0, NULL, 'Chi phí SXKD dở dang dài hạn. Ủy ban nhân dân TP.HCM đã thu hồi, hủy bỏ giao đất cho chủ đầu tư chính năm 2014. Dự án tạm ngưng triển khai chờ phương án của cơ quan nhà nước'),
('VPH_2024_consolidated_inventory_6', 'VPH', 2024, 'consolidated', 'Dự án Quận 9', 'real_estate_project', 7325900105.0, NULL, 'Chi phí đền bù, san lắp và thiết kế hạ tầng cho khu đất 2.798m2 tại Phường Long Trường, Quận 9. Công ty đang đánh giá để triển khai'),
('VPH_2024_consolidated_inventory_7', 'VPH', 2024, 'consolidated', 'Dự án Công viên Nghĩa trang Hòa Bình', 'real_estate_project', 7149302596.0, NULL, 'Quy mô 155.653 m2 tại xã Đa Phước, huyện Bình Chánh. Đang chờ phê duyệt đơn giá tiền sử dụng đất'),
('VPH_2024_consolidated_inventory_8', 'VPH', 2024, 'consolidated', 'Thành phẩm', 'finished_goods', 8861007593.0, 2527064593.0, 'Bao gồm hàng hóa tồn kho, đã trích lập dự phòng giảm giá 2.527.064.593 VND'),
('VPH_2024_consolidated_inventory_9', 'VPH', 2024, 'consolidated', 'Dự án Đất Long Thành', 'real_estate_project', 14063108054.0, NULL, 'Quyền sử dụng lô đất diện tích 415,5 m2 tại xã Lộc An, huyện Long Thành, tỉnh Đồng Nai, thời hạn sử dụng lâu dài. Công ty đang thực hiện thủ tục pháp lý'),
